import React from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { addToCart } from '../redux/cartActions';
import { useNavigate } from 'react-router-dom';
import { SERVICES_DB } from '../utils/database';
import '../styles/Services.css';

const Services = () => {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const { isAuthenticated } = useSelector(state => state.auth);

  const handleAddToCart = (service) => {
    if (!isAuthenticated) {
      alert('Veuillez vous connecter pour ajouter au panier');
      navigate('/login');
      return;
    }

    dispatch(addToCart(service));
    alert(`${service.name} ajouté au panier !`);
  };

  return (
    <div className="services-page">
      <section className="services-section">
        <div className="section-header">
          <div className="section-badge">Nos Services</div>
          <h2 className="section-title">Soins dentaires complets</h2>
          <p className="section-subtitle">
            Des solutions sur mesure adaptées à tous vos besoins dentaires
          </p>
        </div>

        <div className="services-grid">
          {SERVICES_DB.map(service => (
            <div key={service.id} className="service-card">
              <div className="service-badge">{service.icon || '🦷'}</div>
              <div className="service-content">
                <h3>{service.name}</h3>
                <p className="service-description">{service.description}</p>

                <div className="service-meta">
                  <span className="service-duration">⏱️ {service.duration}</span>
                  <span className="service-category">📋 {service.category}</span>
                </div>

                {service.details && service.details.included && (
                  <div className="service-includes">
                    <h4>✓ Inclus:</h4>
                    <ul>
                      {service.details.included.slice(0, 3).map((item, index) => (
                        <li key={index}>{item}</li>
                      ))}
                      {service.details.included.length > 3 && (
                        <li className="more-items">+ {service.details.included.length - 3} autres...</li>
                      )}
                    </ul>
                  </div>
                )}

                <div className="service-footer">
                  <span className="service-price">{service.price}€</span>
                  <button 
                    className="btn btn-primary btn-small"
                    onClick={() => handleAddToCart(service)}
                  >
                    Ajouter au panier
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      </section>
    </div>
  );
};

export default Services;
